import java.io.*;
import javax.servlet.*;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Properly encode user input before outputting it to the response
        String encodedUserInput = encodeForHtml(userInput);

        response.getWriter().println("<p>User input: " + encodedUserInput + "</p>");
    }

    // Method to properly encode user input for HTML output
    private String encodeForHtml(String input) {
        return input != null ?
            input.replace("&", "&amp;")
                 .replace("<", "&lt;")
                 .replace(">", "&gt;")
                 .replace("\"", "&quot;")
                 .replace("'", "&#39;") : "";
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
